import json
import re

with open(var_functions.query_db_14, 'r') as f:
    reviews_2020 = json.load(f)

with open(var_functions.query_db_22, 'r') as f:
    all_books = json.load(f)

book_titles = {}
for book in all_books:
    book_titles[book['book_id']] = book['title']

children_ids = ['bookid_4', 'bookid_14', 'bookid_32', 'bookid_40', 'bookid_48', 'bookid_52', 'bookid_54', 'bookid_55', 'bookid_57', 'bookid_96', 'bookid_99', 'bookid_108', 'bookid_111', 'bookid_116', 'bookid_120', 'bookid_124', 'bookid_130', 'bookid_132', 'bookid_145', 'bookid_146', 'bookid_149', 'bookid_152', 'bookid_158', 'bookid_163', 'bookid_170']

children_ratings = {}
for review in reviews_2020:
    match = re.search(r'purchaseid_(\d+)', review['purchase_id'])
    if match:
        book_id = 'bookid_' + match.group(1)
        if book_id in children_ids:
            if book_id not in children_ratings:
                children_ratings[book_id] = []
            children_ratings[book_id].append(float(review['rating']))

results = []
for book_id in children_ratings:
    ratings = children_ratings[book_id]
    avg = sum(ratings) / len(ratings)
    if avg >= 4.5:
        results.append({'title': book_titles[book_id], 'avg_rating': round(avg, 2), 'review_count': len(ratings)})

results.sort(key=lambda x: (-x['avg_rating'], -x['review_count']))

if not results:
    answer = 'No children books meet the 4.5 rating threshold.'
else:
    lines = ['Children books with average rating >= 4.5 (2020+ reviews):']
    for r in results:
        lines.append('- ' + r['title'] + ' (Avg: ' + str(r['avg_rating']) + ', Count: ' + str(r['review_count']) + ')')
    answer = '\n'.join(lines)

print('__RESULT__:')
print(json.dumps({'answer': answer}))

