    lines.append("No children's books meet the rating threshold.")
else:
    lines.append("Children's books with average rating >= 4.5 (2020+):")
    for book in highly_rated:
        lines.append("- " + book[0] + " (Avg: " + str(book[1]) + ", Reviews: " + str(book[2]) + ")")

answer = "\n".join(lines)
print('__RESULT__:')
print(json.dumps(answer))

